using System.ComponentModel.DataAnnotations;

namespace sv_f581a435a1ff4036b070afe6474c330b.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    public string ReviewBody { get; set; } = string.Empty;
}

using sv_f581a435a1ff4036b070afe6474c330b.Models;

namespace sv_f581a435a1ff4036b070afe6474c330b.Services;

public class ReviewService
{
    /// <summary>
    /// Validates the review against server-side business rules and submits it if valid.
    /// Returns a dictionary of field-specific errors (empty if submission succeeded).
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAndSubmitAsync(ReviewModel review, List<byte[]>? photos)
    {
        var errors = new Dictionary<string, string>();

        if (review.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(review.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        // TODO: Add additional server-side validation rules here.

        if (errors.Count == 0)
        {
            // TODO: Persist the review and photos to a data store.
        }

        return Task.FromResult(errors);
    }
}

@page "/write-review"
@rendermode InteractiveServer
@using sv_f581a435a1ff4036b070afe6474c330b.Models
@using sv_f581a435a1ff4036b070afe6474c330b.Services
@inject ReviewService ReviewService

<PageTitle>Write a Review</PageTitle>

<h1>Write a Review</h1>

@if (_submitted)
{
    <div class="alert alert-success" role="alert">
        <h4>Thank you!</h4>
        <p>Your review has been submitted successfully.</p>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmitAsync" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="productName" class="form-label">Product Name</label>
            <InputText id="productName" class="form-control" @bind-Value="_model.ProductName" />
            <ValidationMessage For="() => _model.ProductName" />
            @if (_serverErrors.ContainsKey(nameof(_model.ProductName)))
            {
                <div class="validation-message">@_serverErrors[nameof(_model.ProductName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="rating" class="form-label">Rating</label>
            <InputNumber id="rating" class="form-control" @bind-Value="_model.Rating" min="1" max="5" />
            <ValidationMessage For="() => _model.Rating" />
            @if (_serverErrors.ContainsKey(nameof(_model.Rating)))
            {
                <div class="validation-message">@_serverErrors[nameof(_model.Rating)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewTitle" class="form-label">Review Title</label>
            <InputText id="reviewTitle" class="form-control" @bind-Value="_model.ReviewTitle" />
            <ValidationMessage For="() => _model.ReviewTitle" />
            @if (_serverErrors.ContainsKey(nameof(_model.ReviewTitle)))
            {
                <div class="validation-message">@_serverErrors[nameof(_model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewBody" class="form-label">Review Body</label>
            <InputTextArea id="reviewBody" class="form-control" rows="5" @bind-Value="_model.ReviewBody" />
            <ValidationMessage For="() => _model.ReviewBody" />
            @if (_serverErrors.ContainsKey(nameof(_model.ReviewBody)))
            {
                <div class="validation-message">@_serverErrors[nameof(_model.ReviewBody)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="photos" class="form-label">Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile id="photos" class="form-control" OnChange="OnPhotosSelected" multiple accept=".jpg,.jpeg,.png" />
            @if (_photoError is not null)
            {
                <div class="validation-message">@_photoError</div>
            }
            @if (_selectedFiles.Count > 0)
            {
                <ul class="list-unstyled mt-2">
                    @foreach (var file in _selectedFiles)
                    {
                        <li><strong>@file.Name</strong> — @FormatSize(file.Size)</li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@_isSubmitting">
            @if (_isSubmitting)
            {
                <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Review</span>
            }
        </button>
    </EditForm>
}

@code {
    private const int MaxFiles = 3;
    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private static readonly string[] AllowedExtensions = [".jpg", ".jpeg", ".png"];

    private ReviewModel _model = new();
    private List<IBrowserFile> _selectedFiles = new();
    private List<byte[]> _photoBuffers = new();
    private string? _photoError;
    private Dictionary<string, string> _serverErrors = new();
    private bool _submitted;
    private bool _isSubmitting;

    private void OnPhotosSelected(InputFileChangeEventArgs e)
    {
        _photoError = null;
        _selectedFiles.Clear();
        _photoBuffers.Clear();

        var files = e.GetMultipleFiles(MaxFiles + 1);

        if (files.Count > MaxFiles)
        {
            _photoError = $"You can upload at most {MaxFiles} photos.";
            return;
        }

        foreach (var file in files)
        {
            var ext = Path.GetExtension(file.Name).ToLowerInvariant();
            if (!AllowedExtensions.Contains(ext))
            {
                _photoError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
                _selectedFiles.Clear();
                return;
            }

            if (file.Size > MaxFileSize)
            {
                _photoError = $"'{file.Name}' exceeds the 5 MB size limit.";
                _selectedFiles.Clear();
                return;
            }

            _selectedFiles.Add(file);
        }
    }

    private async Task HandleSubmitAsync()
    {
        _serverErrors.Clear();
        _isSubmitting = true;

        try
        {
            // Read photo data only if we haven't already buffered them
            if (_photoBuffers.Count == 0 && _selectedFiles.Count > 0)
            {
                foreach (var file in _selectedFiles)
                {
                    using var stream = file.OpenReadStream(MaxFileSize);
                    using var ms = new MemoryStream();
                    await stream.CopyToAsync(ms);
                    _photoBuffers.Add(ms.ToArray());
                }
            }

            var errors = await ReviewService.ValidateAndSubmitAsync(_model, _photoBuffers);

            if (errors.Count > 0)
            {
                _serverErrors = errors;
            }
            else
            {
                _submitted = true;
            }
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        return $"{bytes / (1024.0 * 1024.0):F2} MB";
    }
}

